const body = $input.first().json.body;
const fields = body.data.fields;

let name = '', email = '', phone = '', 
    date = '', time = '', reason = '';

fields.forEach(field => {
  const label = field.label.toLowerCase();
  const value = field.value || '';

  if (label.includes('name')) name = value;
  if (label.includes('email')) email = value;
  if (label.includes('phone')) phone = value;
  if (label.includes('date')) date = value;
  if (label.includes('time')) time = value;
  if (label.includes('reason') || label.includes('message')) reason = value;
});

if (!email) {
  throw new Error('Email not found in form submission');
}

return [{ 
  json: { 
    name, 
    email, 
    phone, 
    date, 
    time, 
    reason,
    submittedAt: new Date().toISOString() 
  } 
}];

const openAIResponse = $input.first().json;

// OpenAI response se text nikalo
const fullText = openAIResponse.message?.content || 
                 openAIResponse.text || 
                 openAIResponse.choices?.[0]?.message?.content || '';

let subject = 'Appointment Confirmation';
let body = fullText;

// SUBJECT aur BODY alag karo
if (fullText.includes('SUBJECT:') && fullText.includes('BODY:')) {
  const subjectMatch = fullText.match(/SUBJECT:\s*(.+?)\n/);
  const bodyMatch = fullText.match(/BODY:\s*([\s\S]+)/);

  if (subjectMatch) subject = subjectMatch[1].trim();
  if (bodyMatch) body = bodyMatch[1].trim();
} else if (fullText.includes('Subject:')) {
  // Agar OpenAI ne Subject: format use kiya
  const subjectMatch = fullText.match(/Subject:\s*(.+?)\n/);
  if (subjectMatch) subject = subjectMatch[1].trim();

  // Subject ke baad baqi sab body hai
  body = fullText.replace(/Subject:\s*.+?\n/, '').trim();
}

// Form data wapis lo
const formData = $('Extract Form Data').first().json;

return [{
  json: {
    subject,
    body,
    clientEmail: formData.email,
    clientName: formData.name,
    appointmentDate: formData.date,
    appointmentTime: formData.time
  }
}];

